diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9ff1e3aa5502..d3c39ab73efc 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -5155,6 +5155,35 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
     }
   }

+  BinaryOperator *SDiv = nullptr;
+  // icmp (sdiv X, Y), X
+  if (BO0 && BO0->getOpcode() == Instruction::SDiv && Op1 == BO0->getOperand(0))
+    SDiv = BO0;
+  // icmp X, (sdiv X, Y)
+  else if (BO1 && BO1->getOpcode() == Instruction::SDiv &&
+           Op0 == BO1->getOperand(0))
+    SDiv = BO1;
+
+  if (SDiv) {
+    // (X / Y) < X  ->  X > 0 (if Y != 0, 1)
+    // (X / Y) >= X ->  X <= 0 (if Y != 0, 1)
+    // (X / Y) == X ->  X == 0 (if Y != 0, 1, -1)
+    // (X / Y) != X ->  X != 0 (if Y != 0, 1, -1)
+    ICmpInst::Predicate SwappedPred =
+        SDiv == BO0 ? Pred : ICmpInst::getSwappedPredicate(Pred);
+    const APInt *C;
+    if (match(SDiv->getOperand(1), m_APInt(C)) && !C->isZero() && !C->isOne()) {
+      if (SwappedPred == ICmpInst::ICMP_SLT || (SwappedPred == ICmpInst::ICMP_EQ && !C->isAllOnes())) {
+        return new ICmpInst(SwappedPred == ICmpInst::ICMP_SLT ? ICmpInst::ICMP_SGT : ICmpInst::ICMP_EQ, SDiv->getOperand(0),
+                            Constant::getNullValue(SDiv->getType()));
+      } else if (SwappedPred == ICmpInst::ICMP_SGE || (SwappedPred == ICmpInst::ICMP_NE && !C->isAllOnes())) {
+        return new ICmpInst(SwappedPred == ICmpInst::ICMP_SGE ? ICmpInst::ICMP_SLE : ICmpInst::ICMP_NE, SDiv->getOperand(0),
+                            Constant::getNullValue(SDiv->getType()));
+      }
+    }
+  }
+
+
   if (BO0 && BO1 && BO0->getOpcode() == BO1->getOpcode() &&
       (BO0->hasOneUse() || BO1->hasOneUse()) &&
       BO0->getOperand(1) == BO1->getOperand(1)) {

